@pytest.mark.api
@pytest.mark.smoke
class TestUserAPI:
    """Test suite for User API endpoints"""

    def test_get_users_list(self, auth_headers):
        """Verify GET /users returns paginated user list"""
        response = requests.get(
            f"{BASE_URL}/users",
            headers=auth_headers,
            params={"page": 1, "limit": 10}
        )

        assert response.status_code == 200
        data = response.json()

        assert "users" in data
        assert "total" in data
        assert "page" in data
        assert isinstance(data["users"], list)
        assert len(data["users"]) <= 10

    def test_create_user(self, auth_headers, test_user_data):
        """Verify POST /users creates new user"""
        response = requests.post(
            f"{BASE_URL}/users",
            headers=auth_headers,
            json=test_user_data
        )

        assert response.status_code == 201
        data = response.json()

        assert data["username"] == test_user_data["username"]
        assert data["email"] == test_user_data["email"]
        assert "id" in data
        assert "created_at" in data

        # Cleanup: Store user ID for deletion
        pytest.created_user_id = data["id"]

    def test_get_user_by_id(self, auth_headers):
        """Verify GET /users/{id} returns specific user"""
        if not hasattr(pytest, "created_user_id"):
            pytest.skip("No user created in previous test")

        response = requests.get(
            f"{BASE_URL}/users/{pytest.created_user_id}",
            headers=auth_headers
        )

        assert response.status_code == 200
        data = response.json()

        assert data["id"] == pytest.created_user_id
        assert "username" in data
        assert "email" in data

    def test_update_user(self, auth_headers):
        """Verify PATCH /users/{id} updates user"""
        if not hasattr(pytest, "created_user_id"):
            pytest.skip("No user created in previous test")

        update_data = {"first_name": "Updated"}

        response = requests.patch(
            f"{BASE_URL}/users/{pytest.created_user_id}",
            headers=auth_headers,
            json=update_data
        )

        assert response.status_code == 200
        data = response.json()

        assert data["first_name"] == "Updated"

    def test_delete_user(self, auth_headers):
        """Verify DELETE /users/{id} removes user"""
        if not hasattr(pytest, "created_user_id"):
            pytest.skip("No user created in previous test")

        response = requests.delete(
            f"{BASE_URL}/users/{pytest.created_user_id}",
            headers=auth_headers
        )

        assert response.status_code == 204

        # Verify deletion
        get_response = requests.get(
            f"{BASE_URL}/users/{pytest.created_user_id}",
            headers=auth_headers
        )
        assert get_response.status_code == 404


