@pytest.mark.api
@pytest.mark.validation
class TestAPIValidation:
    """Test API input validation and error handling"""

    @pytest.mark.parametrize("invalid_data,expected_error", [
        ({"username": "ab"}, "Username must be at least 3 characters"),
        ({"username": "validuser"}, "Email is required"),
        ({"username": "validuser", "email": "invalid"}, "Invalid email format"),
        ({"username": "user", "email": "user@test.com", "role": "superadmin"}, "Invalid role"),
    ])
    def test_create_user_validation(self, auth_headers, invalid_data, expected_error):
        """Test user creation validation errors"""
        response = requests.post(
            f"{BASE_URL}/users",
            headers=auth_headers,
            json=invalid_data
        )

        assert response.status_code == 400
        data = response.json()

        assert "error" in data
        assert expected_error in data["error"]["message"]

    def test_unauthorized_access(self):
        """Verify API requires authentication"""
        response = requests.get(f"{BASE_URL}/users")

        assert response.status_code == 401
        assert "error" in response.json()

    def test_invalid_token(self):
        """Verify invalid token is rejected"""
        headers = {"Authorization": "Bearer invalid_token"}

        response = requests.get(
            f"{BASE_URL}/users",
            headers=headers
        )

        assert response.status_code == 401

    def test_user_not_found(self, auth_headers):
        """Verify 404 for non-existent user"""
        response = requests.get(
            f"{BASE_URL}/users/99999",
            headers=auth_headers
        )

        assert response.status_code == 404
        data = response.json()

        assert "error" in data
        assert "not found" in data["error"]["message"].lower()


