@pytest.mark.api
@pytest.mark.performance
class TestAPIPerformance:
    """Test API response time and throughput"""

    def test_api_response_time(self, auth_headers):
        """Verify API responds within acceptable time"""
        start = time.time()
        response = requests.get(
            f"{BASE_URL}/users",
            headers=auth_headers
        )
        duration = time.time() - start

        assert response.status_code == 200
        assert duration < 1.0, f"API took {duration:.2f}s (expected < 1s)"

    def test_concurrent_requests(self, auth_headers):
        """Test API handles concurrent requests"""
        import concurrent.futures

        def make_request():
            return requests.get(
                f"{BASE_URL}/users",
                headers=auth_headers
            )

        with concurrent.futures.ThreadPoolExecutor(max_workers=10) as executor:
            futures = [executor.submit(make_request) for _ in range(10)]
            results = [f.result() for f in concurrent.futures.as_completed(futures)]

        # All requests should succeed
        assert all(r.status_code == 200 for r in results)


