@pytest.mark.api
@pytest.mark.contract
class TestAPIContract:
    """Test API adheres to expected contract/schema"""

    def test_user_schema(self, auth_headers):
        """Verify user object matches expected schema"""
        response = requests.get(
            f"{BASE_URL}/users",
            headers=auth_headers
        )

        assert response.status_code == 200
        users = response.json()["users"]

        if users:
            user = users[0]
            required_fields = ["id", "username", "email", "created_at"]

            for field in required_fields:
                assert field in user, f"Missing required field: {field}"

            # Type validation
            assert isinstance(user["id"], int)
            assert isinstance(user["username"], str)
            assert isinstance(user["email"], str)

    def test_pagination_schema(self, auth_headers):
        """Verify pagination response structure"""
        response = requests.get(
            f"{BASE_URL}/users?page=1&limit=5",
            headers=auth_headers
        )

        assert response.status_code == 200
        data = response.json()

        required_fields = ["users", "total", "page", "limit", "pages"]

        for field in required_fields:
            assert field in data, f"Missing pagination field: {field}"

        assert isinstance(data["users"], list)
        assert isinstance(data["total"], int)
        assert data["page"] == 1
        assert data["limit"] == 5


